import * as React from "react";
import { cn } from "../utils/cn";

interface PriceDisplayProps {
  amount: number;
  className?: string;
  size?: "sm" | "md" | "lg";
  strikethrough?: boolean;
}

const sizeStyles = {
  sm: "text-sm",
  md: "text-base",
  lg: "text-xl",
};

export function PriceDisplay({ amount, className, size = "md", strikethrough = false }: PriceDisplayProps) {
  const formatted = new Intl.NumberFormat("fr-CM", {
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(amount);

  return (
    <span
      className={cn(
        "font-bold tabular-nums",
        size === "lg" ? "text-2xl" : sizeStyles[size],
        strikethrough && "line-through text-gray-400",
        !strikethrough && "text-primary",
        className,
      )}
    >
      {formatted}{" "}
      <span className={cn("font-normal", size === "lg" ? "text-sm" : "text-xs")}>FCFA</span>
    </span>
  );
}
